INSERT INTO Spell (name, description, casting_time, range_distance, duration, damage, is_verbal, is_somatic, is_material, spellLevel, school) VALUES
('Acalmar Emoções', 'Você tenta suprimir emoções fortes em um grupo de pessoas em uma esfera de 6 metros.', '1 ação', 18, 'Concentração, até 1 minuto', NULL, TRUE, TRUE, FALSE, 2, 'Encantamento'),
('Adivinhação', 'Você faz uma única pergunta a respeito de um objetivo ou evento que irá ocorrer dentro de 7 dias.', '1 ação', 0, 'Instantânea', NULL, TRUE, TRUE, TRUE, 4, 'Adivinhação'),
('Ajuda', 'O máximo de pontos de vida e os pontos de vida atuais de cada alvo aumentam em 5.', '1 ação', 9, '8 horas', NULL, TRUE, TRUE, TRUE, 2, 'Abjuração'),
('Alarme', 'Você coloca um alarme para intrusos em uma área que não seja maior que 6 metros cúbicos.', '1 minuto', 9, '8 horas', NULL, TRUE, TRUE, TRUE, 1, 'Abjuração'),
('Aliado Planar', 'Você suplica a uma entidade transcendental por ajuda de um celestial, corruptor ou elemental.', '10 minutos', 18, 'Instantânea', NULL, TRUE, TRUE, FALSE, 6, 'Conjuração'),
('Aljava Veloz', 'Transmuta sua aljava para que ela produza um suprimento interminável de munições não-mágicas.', '1 ação bônus', 1, 'Concentração, até 1 minuto', NULL, TRUE, TRUE, TRUE, 5, 'Transmutação'),
('Alterar Forma', 'Você assume a forma de uma criatura diferente com ND igual ao seu nível ou menor.', '1 ação', 0, 'Concentração, até 1 hora', NULL, TRUE, TRUE, TRUE, 9, 'Transmutação'),
('Alterar-se', 'Você assume uma forma diferente: Adaptação Aquática, Mudar Aparência ou Armas Naturais.', '1 ação', 0, 'Concentração, até 1 hora', '1d6', TRUE, TRUE, FALSE, 2, 'Transmutação'),
('Amizade', 'Você terá vantagem em todos os testes de Carisma direcionados a uma criatura não hostil.', '1 ação', 0, 'Concentração, até 1 minuto', NULL, FALSE, TRUE, TRUE, 0, 'Encantamento'),
('Amizade Animal', 'Convence uma besta que você não quer prejudicá-la através de um teste de Sabedoria.', '1 ação', 9, '24 horas', NULL, TRUE, TRUE, TRUE, 1, 'Encantamento'),
('Ampliar Plantas', 'Canaliza vitalidade nas plantas tornando-as espessas ou fertilizando a terra.', '1 ação ou 8 horas', 45, 'Instantânea', NULL, TRUE, TRUE, FALSE, 3, 'Transmutação'),
('Âncora Planar', 'Você tenta obrigar um celestial, corruptor, elemental ou fada a servi-lo.', '1 hora', 18, '24 horas', NULL, TRUE, TRUE, TRUE, 5, 'Abjuração'),
('Andar na Água', 'Concede a habilidade de se mover através de qualquer superfície líquida como se fosse chão sólido.', '1 ação', 9, '1 hora', NULL, TRUE, TRUE, TRUE, 3, 'Transmutação'),
('Animar Mortos', 'Cria um servo morto-vivo esqueleto ou zumbi a partir de um corpo ou ossos.', '1 minuto', 3, 'Instantânea', NULL, TRUE, TRUE, TRUE, 3, 'Necromancia'),
('Animar Objetos', 'Até dez objetos não-mágicos ganham vida e tornam-se criaturas sob seu controle.', '1 ação', 36, 'Concentração, até 1 minuto', '1d4+4', TRUE, TRUE, FALSE, 5, 'Transmutação'),
('Antipatia/Simpatia', 'Envolve um alvo com uma aura que atrai ou repele criaturas de um tipo específico.', '1 hora', 18, '10 dias', NULL, TRUE, TRUE, TRUE, 8, 'Encantamento'),
('Aprimorar Habilidade', 'Agracia uma criatura com um aprimoramento mágico como Vigor do Urso ou Agilidade do Gato.', '1 ação', 1, 'Concentração, até 1 hora', NULL, TRUE, TRUE, TRUE, 2, 'Transmutação'),
('Aprisionamento', 'Cria um impedimento mágico para imobilizar uma criatura de forma permanente até ser dissipada.', '1 minuto', 9, 'Até ser dissipada', NULL, TRUE, TRUE, TRUE, 9, 'Abjuração'),
('Arca Secreta de Leomund', 'Esconde um baú e todo o seu conteúdo no Plano Etéreo para ser revocado depois.', '1 ação', 1, 'Instantânea', NULL, TRUE, TRUE, TRUE, 4, 'Conjuração'),
('Área Escorregadia', 'Cobre o solo com graxa tornando a área em terreno difícil e derrubando criaturas.', '1 ação', 18, '1 minuto', NULL, TRUE, TRUE, TRUE, 1, 'Conjuração'),
('Arma Elemental', 'Uma arma não-mágica se torna mágica e causa dano extra de ácido, elétrico, frio, fogo ou trovão.', '1 ação', 1, 'Concentração, até 1 hora', '1d4', TRUE, TRUE, FALSE, 3, 'Transmutação'),
('Arma Espiritual', 'Cria uma arma espectral flutuante que realiza ataques corpo-a-corpo com magia.', '1 ação bônus', 18, '1 minuto', '1d8', TRUE, TRUE, FALSE, 2, 'Evocação'),
('Arma Mágica', 'Toca uma arma não-mágica concedendo +1 de bônus nas jogadas de ataque e dano.', '1 ação bônus', 1, 'Concentração, até 1 hora', NULL, TRUE, TRUE, FALSE, 2, 'Transmutação'),
('Armadura Arcana', 'Uma energia mágica protetora envolve um alvo sem armadura, definindo a CA base para 13 + Des.', '1 ação', 1, '8 horas', NULL, TRUE, TRUE, TRUE, 1, 'Abjuração'),
('Armadura de Agathys', 'Um frio espectral cobre você, garantindo 5 PV temporários e causando 5 de dano de frio a atacantes.', '1 ação', 0, '1 hora', '5', TRUE, TRUE, TRUE, 1, 'Abjuração'),
('ArromBAR', 'Destranca ou desbloqueia uma porta, baú ou algemas, suprimindo trancas arcanas.', '1 ação', 18, 'Instantânea', NULL, TRUE, FALSE, FALSE, 2, 'Transmutação'),
('Assassino Fantasmagórico', 'Cria uma manifestação ilusória dos medos mais profundos de um alvo causando dano psíquico.', '1 ação', 36, 'Concentração, até 1 minuto', '4d10', TRUE, TRUE, FALSE, 4, 'Ilusão'),
('Ataque Certeiro', 'Garante uma breve intuição sobre as defesas do alvo, dando vantagem na próxima jogada de ataque.', '1 ação', 9, 'Concentração, até 1 rodada', NULL, FALSE, TRUE, FALSE, 0, 'Adivinhação'),
('Ataque Visual', 'Seus olhos emitem poder terrível que pode adormecer, apavorar ou adoecer criaturas.', '1 ação', 0, 'Concentração, até 1 minuto', NULL, TRUE, TRUE, FALSE, 6, 'Necromancia'),
('Augúrio', 'Você recebe um presságio de uma entidade sobre os resultados de uma ação planejada.', '1 minuto', 0, 'Instantânea', NULL, TRUE, TRUE, TRUE, 2, 'Adivinhação'),
('Aumentar/Reduzir', 'Faz com que uma criatura ou objeto fique maior ou menor, alterando seu peso e dano.', '1 ação', 9, 'Concentração, até 1 minuto', '1d4', TRUE, TRUE, TRUE, 2, 'Transmutação'),
('Aura de Pureza', 'Energia purificante impede doenças e concede resistência a veneno em uma aura de 9 metros.', '1 ação', 0, 'Concentração, até 10 minutos', NULL, TRUE, FALSE, FALSE, 4, 'Abjuração'),
('Aura de Vida', 'Criaturas não-hostis na aura ganham resistência a dano necrótico e recuperam 1 PV se estiverem com 0.', '1 ação', 0, 'Concentração, até 10 minutos', NULL, TRUE, FALSE, FALSE, 4, 'Abjuração'),
('Aura de Vitalidade', 'Você pode usar uma ação bônus para fazer com que uma criatura na aura recupere 2d6 PV.', '1 ação', 0, 'Concentração, até 1 minuto', NULL, TRUE, FALSE, FALSE, 3, 'Evocação'),
('Aura Mágica de Nystul', 'Coloca uma ilusão em uma criatura ou objeto para enganar magias de adivinhação.', '1 ação', 1, '24 horas', NULL, TRUE, TRUE, TRUE, 2, 'Ilusão'),
('Aura Sagrada', 'Luz divina concede vantagem em testes de resistência e impõe desvantagem em ataques contra aliados.', '1 ação', 0, 'Concentração, até 1 minuto', NULL, TRUE, TRUE, TRUE, 8, 'Abjuração'),
('Auxílio Divino', 'Sua oração fortalece você, fazendo com que seus ataques com arma causem 1d4 de dano radiante extra.', '1 ação bônus', 0, 'Concentração, até 1 minuto', '1d4', TRUE, TRUE, FALSE, 1, 'Evocação'),
('Banimento', 'Tenta enviar uma criatura para outro plano de existência se ela falhar no teste de Carisma.', '1 ação', 9, 'Concentração, até 1 minuto', NULL, TRUE, TRUE, TRUE, 4, 'Abjuração'),
('Banquete de Heróis', 'Traz um grande banquete que cura doenças, venenos e aumenta o máximo de pontos de vida.', '10 minutos', 9, 'Instantânea', NULL, TRUE, TRUE, TRUE, 6, 'Conjuração'),
('Barreira de Lâminas', 'Cria uma muralha de lâminas giratórias que causa 6d10 de dano cortante.', '1 ação', 24, 'Concentração, até 10 minutos', '6d10', TRUE, TRUE, FALSE, 6, 'Evocação'),
('Bênção', 'Abençoa até três criaturas adicionando 1d4 às suas jogadas de ataque e testes de resistência.', '1 ação', 9, 'Concentração, até 1 minuto', NULL, TRUE, TRUE, TRUE, 1, 'Encantamento'),
